@Controller
class SamlLoginController {
    private final SamlAuthService authService;
    private final RedirectStrategy redirectStrategy = new DefaultRedirectStrategy();

    SamlLoginController(SamlAuthService authService) {
        this.authService = authService;
    }

    @GetMapping("/saml/login")
    public void login(HttpServletRequest request, HttpServletResponse response) throws Exception {
        String relayState = Optional.ofNullable(request.getParameter("relayState")).orElse("/");
        redirectStrategy.sendRedirect(request, response, authService.buildRedirectUrl(relayState));
    }

    @GetMapping("/saml/logout")
    public void logout(HttpServletRequest request, HttpServletResponse response) throws Exception {
        new SecurityContextLogoutHandler().logout(request, response, SecurityContextHolder.getContext().getAuthentication());
        response.setContentType(MediaType.TEXT_PLAIN_VALUE);
        response.getWriter().write("Logged out");
    }
}

