final class SamlAuthenticationEntryPoint implements AuthenticationEntryPoint {
    private final SamlAuthService authService;
    private final RedirectStrategy redirectStrategy = new DefaultRedirectStrategy();

    SamlAuthenticationEntryPoint(SamlAuthService authService) {
        this.authService = authService;
    }

    @Override
    public void commence(HttpServletRequest request, HttpServletResponse response, org.springframework.security.core.AuthenticationException authException) throws java.io.IOException {
        try {
            redirectStrategy.sendRedirect(request, response, authService.buildRedirectUrl(request.getRequestURI()));
        } catch (Exception e) {
            response.sendError(500, e.getMessage());
        }
    }
}

final class SamlAssertionConsumerServiceFilter extends OncePerRequestFilter {
    private final SamlAuthService authService;

    SamlAssertionConsumerServiceFilter(SamlAuthService authService) {
        this.authService = authService;
    }

    @Override
    protected boolean shouldNotFilter(HttpServletRequest request) {
        return !"/saml/acs".equals(request.getRequestURI()) || !"POST".equalsIgnoreCase(request.getMethod());
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain) throws ServletException, java.io.IOException {
        String samlResponse = request.getParameter("SAMLResponse");
        if (StringUtils.hasText(samlResponse)) {
            try {
                Authentication authentication = authService.authenticateResponse(samlResponse);
                SecurityContextHolder.getContext().setAuthentication(authentication);
                HttpSession session = request.getSession(true);
                session.setAttribute("SPRING_SECURITY_CONTEXT", SecurityContextHolder.getContext());
                response.sendRedirect(Optional.ofNullable(request.getParameter("RelayState")).orElse("/"));
                return;
            } catch (Exception e) {
                response.sendError(401, "Invalid SAML response");
                return;
            }
        }
        filterChain.doFilter(request, response);
    }
}

